content:
{
  "sentences": [
    {
      "text": "我會說一點中文，可是還不太會寫字。",
      "pinyin": "Wǒ huì shuō yīdiǎn Zhōngwén, kěshì hái bù tài huì xiě zì.",
      "pinyin_numeric": "wo3 hui4 shuo1 yi1dian3 Zhong1wen2, ke3shi4 hai2 bu4 tai4 hui4 xie3 zi4.",
      "translation_en": "I can speak a little Chinese, but I still can't write characters very well.",
      "translation_ko": "저는 중국어를 조금 할 수 있지만, 아직 글씨 쓰기는 잘 못해요."
    },
    {
      "text": "他完全不會說中文，可是正在努力學。",
      "pinyin": "Tā wánquán bù huì shuō Zhōngwén, kěshì zhèngzài nǔlì xué.",
      "pinyin_numeric": "ta1 wan2quan2 bu4 hui4 shuo1 Zhong1wen2, ke3shi4 zheng4zai4 nu3li4 xue2.",
      "translation_en": "He can't speak Chinese at all, but he is working hard to learn.",
      "translation_ko": "그는 중국어를 전혀 못 하지만, 열심히 배우고 있어요."
    },
    {
      "text": "我已經學了半年中文，現在會聽懂簡單的句子。",
      "pinyin": "Wǒ yǐjīng xué le bàn nián Zhōngwén, xiànzài huì tīng dǒng jiǎndān de jùzi.",
      "pinyin_numeric": "wo3 yi3jing1 xue2 le ban4 nian2 Zhong1wen2, xian4zai4 hui4 ting1 dong3 jian3dan1 de ju4zi.",
      "translation_en": "I have been studying Chinese for half a year, and now I can understand simple sentences.",
      "translation_ko": "저는 중국어를 반 년 동안 배웠고, 이제 간단한 문장을 알아들을 수 있어요."
    },
    {
      "text": "她不太會煮菜，可是想慢慢學。",
      "pinyin": "Tā bù tài huì zhǔ cài, kěshì xiǎng màn man xué.",
      "pinyin_numeric": "ta1 bu4 tai4 hui4 zhu3 cai4, ke3shi4 xiang3 man4 man xue2.",
      "translation_en": "She is not very good at cooking, but she wants to learn slowly.",
      "translation_ko": "그녀는 요리를 잘 못하지만, 천천히 배우고 싶어해요."
    },
    {
      "text": "你會不會開車？我已經會了，可是還不太熟。",
      "pinyin": "Nǐ huì bù huì kāi chē? Wǒ yǐjīng huì le, kěshì hái bù tài shú.",
      "pinyin_numeric": "ni3 hui4 bu4 hui4 kai1 che1? wo3 yi3jing1 hui4 le, ke3shi4 hai2 bu4 tai4 shu2.",
      "translation_en": "Can you drive? I already can, but I'm still not very familiar with it.",
      "translation_ko": "운전할 수 있어요? 저는 이미 할 수 있지만, 아직 익숙하지 않아요."
    },
    {
      "text": "他會彈鋼琴，也會唱歌，能力很好。",
      "pinyin": "Tā huì tán gāngqín, yě huì chànggē, nénglì hěn hǎo.",
      "pinyin_numeric": "ta1 hui4 tan2 gang1qin2, ye3 hui4 chang4ge1, neng2li4 hen3 hao3.",
      "translation_en": "He can play the piano and also sing; his ability is very good.",
      "translation_ko": "그는 피아노를 칠 수 있고 노래도 부를 수 있어서 능력이 아주 좋아요."
    },
    {
      "text": "我最近在學游泳，已經會一點了，可是還不太會換氣。",
      "pinyin": "Wǒ zuìjìn zài xué yóuyǒng, yǐjīng huì yīdiǎn le, kěshì hái bù tài huì huàn qì.",
      "pinyin_numeric": "wo3 zui4jin4 zai4 xue2 you2yong3, yi3jing1 hui4 yi1dian3 le, ke3shi4 hai2 bu4 tai4 hui4 huan4 qi4.",
      "translation_en": "I am learning to swim recently; I can already do a little, but I still can't breathe properly.",
      "translation_ko": "저는 최근에 수영을 배우고 있어요. 조금 할 수 있지만, 아직 호흡을 잘 못해요."
    },
    {
      "text": "你會不會說中文？當然會，我已經學了好幾個月了。",
      "pinyin": "Nǐ huì bù huì shuō Zhōngwén? Dāngrán huì, wǒ yǐjīng xué le hǎo jǐ gè yuè le.",
      "pinyin_numeric": "ni3 hui4 bu4 hui4 shuo1 Zhong1wen2? dang1ran2 hui4, wo3 yi3jing1 xue2 le hao3 ji3 ge4 yue4 le.",
      "translation_en": "Can you speak Chinese? Of course I can; I have been studying for several months.",
      "translation_ko": "중국어를 할 수 있어요? 물론 할 수 있어요. 몇 달 동안 배웠거든요."
    },
    {
      "text": "他不會騎車，可是正在學，進步很快。",
      "pinyin": "Tā bù huì qí chē, kěshì zhèngzài xué, jìnbù hěn kuài.",
      "pinyin_numeric": "ta1 bu4 hui4 qi2 che1, ke3shi4 zheng4zai4 xue2, jin4bu4 hen3 kuai4.",
      "translation_en": "He can't ride a bike, but he is learning and improving quickly.",
      "translation_ko": "그는 자전거를 못 타지만, 배우고 있고 발전이 빨라요."
    },
    {
      "text": "我覺得學語言很難，可是慢慢學就會進步。",
      "pinyin": "Wǒ juéde xué yǔyán hěn nán, kěshì màn man xué jiù huì jìnbù.",
      "pinyin_numeric": "wo3 jue2de xue2 yu3yan2 hen3 nan2, ke3shi4 man4 man xue2 jiu4 hui4 jin4bu4.",
      "translation_en": "I think learning a language is difficult, but if you learn slowly, you will improve.",
      "translation_ko": "언어를 배우는 것은 어렵다고 생각하지만, 천천히 배우면 발전할 거예요."
    }
  ]
}
